"""
Workflow → DrissionPage Python script exporter.

Each command type has its own emit_* function for clean separation.
"""

import json
from typing import Any

from src.repo import runtime_models as models


def build_python(wf: models.Workflow, flat_nodes: list[models.WorkflowNode], repo_root: str = "") -> list[str]:
    """Generate DrissionPage Python lines from a workflow and its nodes."""
    print(f"[exporter] building python for '{wf.name}' with {len(flat_nodes)} nodes")
    lines = [
        "# AUTO-GENERATED by workflow exporter",
        "# DO NOT EDIT — changes will be overwritten",
        "",
        "import sys, os",
        f"_repo = os.environ.get('RPA_REPO_ROOT', {repr(repo_root)})",
        "_project_root = os.path.dirname(_repo)",
        "if _project_root and _project_root not in sys.path:",
        "    sys.path.insert(0, _project_root)",
        "",
        "from src.repo.chrome_utils import connect_chrome",
        "",
        "# Workflow error handler — maps traceback back to workflow node",
        "import traceback, re",
        "",
        "def _wf_excepthook(exc_type, exc_value, tb):",
        "    node_info = None",
        "    t = tb",
        "    while t:",
        "        co = t.tb_frame.f_code",
        "        if co.co_filename == __file__:",
        "            lineno = t.tb_lineno",
        "            try:",
        "                with open(__file__, 'r', encoding='utf-8') as f:",
        "                    src = f.readlines()",
        "                for i in range(lineno - 1, -1, -1):",
        "                    m = re.search(r'# WF_NODE id=(\\d+) type=(\\S+) label=(.+)', src[i])",
        "                    if m:",
        "                        node_info = {'id': int(m.group(1)), 'type': m.group(2), 'label': m.group(3).strip()}",
        "                        break",
        "            except Exception:",
        "                pass",
        "            if node_info:",
        "                break",
        "        t = t.tb_next",
        "    if node_info:",
        "        print(f\"[WF_ERROR] 指令 #{node_info['id']} ({node_info['type']}) {node_info['label']}\", file=sys.stderr)",
        "    traceback.print_exception(exc_type, exc_value, tb)",
        "",
        "sys.excepthook = _wf_excepthook",
        "",
        f"# Workflow: {wf.name}",
        f"# URL: {wf.url or 'TODO'}",
        "",
        "tab = connect_chrome()",
        "if not tab:",
        "    raise RuntimeError('无法连接到 Chrome，请确保 Chrome 已启动并开启了远程调试端口 9222')",
    ]
    if wf.url:
        lines.append(f"tab.get('{wf.url}')")
    lines.append("")

    # Build parent→children map
    by_parent: dict[int | None, list[models.WorkflowNode]] = {}
    for n in flat_nodes:
        pid = n.parent_id
        by_parent.setdefault(pid, []).append(n)
    for children in by_parent.values():
        children.sort(key=lambda n: n.order)

    # Collect results container
    lines.append("_results = []")
    lines.append("")

    def _emit(node: models.WorkflowNode, depth: int = 0) -> None:
        extra = json.loads(node.extra) if node.extra else {}
        _emit_dispatch(node, extra, depth, by_parent, lines)

    # Emit root nodes
    for n in by_parent.get(None, []):
        _emit(n, 0)

    lines.append("")
    lines.append("print('Workflow completed')")
    lines.append(f"print(f'Results: {{len(_results)}} items')")
    return lines


def _indent(depth: int) -> str:
    return "    " * depth


def _loc_call(node: models.WorkflowNode, extra: dict) -> str:
    """Build tab.ele('...') style locator call."""
    loc = (node.locator or "").replace("'", "\\'")
    method = node.method or "ele"
    if not loc:
        return "tab"
    return f"tab.{method}('{loc}')"


def _var_ref(name: str) -> str:
    """Sanitize variable name."""
    return name.strip() if name else "_tmp"


def _emit_dispatch(node: models.WorkflowNode, extra: dict, depth: int,
                   by_parent: dict, lines: list[str]) -> None:
    prefix = _indent(depth)
    from src.runtime.workflow.commands import COMMAND_REGISTRY
    cmd = COMMAND_REGISTRY.get(node.type, {})
    label = cmd.get("label", node.type)
    lines.append(f"{prefix}# WF_NODE id={node.id} type={node.type} label={label}")
    handler = _EMIT_HANDLERS.get(node.type)

    if handler:
        handler(node, extra, depth, prefix, by_parent, lines)
    else:
        # Unknown type — emit a placeholder
        loc = _loc_call(node, extra)
        lines.append(f"{prefix}# TODO: {node.type} -> {loc}")


# ═══════════════════════════════════════════════════════════════════
# Emit handlers per command type
# ═══════════════════════════════════════════════════════════════════

_EMIT_HANDLERS: dict[str, Any] = {}


def _handler(name: str):
    def decorator(fn):
        _EMIT_HANDLERS[name] = fn
        return fn
    return decorator


# ── Navigation ────────────────────────────────────────────────────

@_handler("navigate")
def _emit_navigate(node, extra, depth, prefix, by_parent, lines):
    url = (extra.get("url") or "").replace("'", "\\'")
    wait = extra.get("waitLoad", True)
    timeout = extra.get("timeout", 30)
    if wait:
        lines.append(f"{prefix}tab.get('{url}')")
    else:
        lines.append(f"{prefix}tab.get('{url}', go_timeout={timeout})")


@_handler("goBack")
def _emit_goBack(node, extra, depth, prefix, by_parent, lines):
    lines.append(f"{prefix}tab.back()")


@_handler("goForward")
def _emit_goForward(node, extra, depth, prefix, by_parent, lines):
    lines.append(f"{prefix}tab.forward()")


@_handler("refresh")
def _emit_refresh(node, extra, depth, prefix, by_parent, lines):
    if extra.get("hardReload"):
        lines.append(f"{prefix}tab.refresh(ignore_cache=True)")
    else:
        lines.append(f"{prefix}tab.refresh()")


@_handler("newTab")
def _emit_newTab(node, extra, depth, prefix, by_parent, lines):
    url = extra.get("url", "").replace("'", "\\'")
    if url:
        lines.append(f"{prefix}tab.new_tab('{url}')")
    else:
        lines.append(f"{prefix}tab.new_tab()")


@_handler("closeTab")
def _emit_closeTab(node, extra, depth, prefix, by_parent, lines):
    lines.append(f"{prefix}tab.close_tabs(tab)")


@_handler("switchTab")
def _emit_switchTab(node, extra, depth, prefix, by_parent, lines):
    by = extra.get("by", "index")
    value = extra.get("value", "")
    if by == "index":
        lines.append(f"{prefix}tab.to_tab({value})")
    elif by == "url":
        lines.append(f"{prefix}tab.to_tab(url='{value}')")
    elif by == "title":
        lines.append(f"{prefix}tab.to_tab(title='{value}')")


@_handler("switchToFrame")
def _emit_switchToFrame(node, extra, depth, prefix, by_parent, lines):
    loc = (node.locator or "").replace("'", "\\'")
    lines.append(f"{prefix}tab.to_frame('{loc}')")


@_handler("switchToMain")
def _emit_switchToMain(node, extra, depth, prefix, by_parent, lines):
    lines.append(f"{prefix}tab.to_main()")


@_handler("getCurrentUrl")
def _emit_getCurrentUrl(node, extra, depth, prefix, by_parent, lines):
    var = _var_ref(extra.get("varName", "currentUrl"))
    lines.append(f"{prefix}{var} = tab.url")


@_handler("getPageTitle")
def _emit_getPageTitle(node, extra, depth, prefix, by_parent, lines):
    var = _var_ref(extra.get("varName", "pageTitle"))
    lines.append(f"{prefix}{var} = tab.title")


