# ── Variables ─────────────────────────────────────────────────────

@_handler("setVar")
def _emit_setVar(node, extra, depth, prefix, by_parent, lines):
    var = _var_ref(extra.get("name", "x"))
    value = extra.get("value", "")
    vtype = extra.get("valueType", "string")
    if vtype == "number":
        lines.append(f"{prefix}{var} = {value}")
    elif vtype == "bool":
        val = "True" if str(value).lower() in ("true", "1", "yes") else "False"
        lines.append(f"{prefix}{var} = {val}")
    elif vtype == "list":
        lines.append(f"{prefix}{var} = []")
    else:
        val = str(value).replace("'", "\\'")
        lines.append(f"{prefix}{var} = '{val}'")


@_handler("appendToList")
def _emit_appendToList(node, extra, depth, prefix, by_parent, lines):
    list_var = _var_ref(extra.get("listName", "items"))
    value = str(extra.get("value", "")).replace("'", "\\'")
    lines.append(f"{prefix}{list_var}.append('{value}')")


@_handler("stringConcat")
def _emit_stringConcat(node, extra, depth, prefix, by_parent, lines):
    target = _var_ref(extra.get("targetVar", "result"))
    parts = [extra.get("part1", ""), extra.get("part2", ""), extra.get("part3", "")]
    parts = [p.replace("'", "\\'") for p in parts if p]
    if parts:
        joined = " + ".join(f"'{p}'" for p in parts)
        lines.append(f"{prefix}{target} = {joined}")
    else:
        lines.append(f"{prefix}{target} = ''")


@_handler("increment")
def _emit_increment(node, extra, depth, prefix, by_parent, lines):
    var = _var_ref(extra.get("varName", "count"))
    step = extra.get("step", 1)
    lines.append(f"{prefix}{var} += {step}")


# ── Output ────────────────────────────────────────────────────────

@_handler("log")
def _emit_log(node, extra, depth, prefix, by_parent, lines):
    msg = (extra.get("message") or "").replace("'", "\\'")
    level = extra.get("level", "info")
    lines.append(f"{prefix}print('[{level.upper()}] {msg}')")


@_handler("pushItem")
def _emit_pushItem(node, extra, depth, prefix, by_parent, lines):
    expr = extra.get("dataExpr", "{}")
    # Try to parse as JSON for pretty printing, fall back to raw
    try:
        parsed = json.loads(expr)
        expr_str = json.dumps(parsed, ensure_ascii=False, indent=None).replace("'", "\\'")
    except Exception:
        expr_str = expr.replace("'", "\\'")
    lines.append(f"{prefix}_results.append({expr_str})")


@_handler("takeScreenshot")
def _emit_takeScreenshot(node, extra, depth, prefix, by_parent, lines):
    path = (extra.get("savePath") or "screenshot.png").replace("'", "\\'")
    full = extra.get("fullPage", False)
    loc = extra.get("locator", "").replace("'", "\\'")
    if loc:
        lines.append(f"{prefix}tab.ele('{loc}').get_screenshot(path='{path}')")
    elif full:
        lines.append(f"{prefix}tab.get_screenshot(path='{path}', full_page=True)")
    else:
        lines.append(f"{prefix}tab.get_screenshot(path='{path}')")


@_handler("saveToFile")
def _emit_saveToFile(node, extra, depth, prefix, by_parent, lines):
    data_var = _var_ref(extra.get("dataVar", "data"))
    path = (extra.get("filePath") or "data.json").replace("'", "\\'")
    fmt = extra.get("format", "json")
    if fmt == "json":
        lines.append(f"{prefix}import json")
        lines.append(f"{prefix}with open('{path}', 'w', encoding='utf-8') as f:")
        lines.append(f"{prefix}    json.dump({data_var}, f, ensure_ascii=False, indent=2)")
    else:
        lines.append(f"{prefix}import csv")
        lines.append(f"{prefix}with open('{path}', 'w', newline='', encoding='utf-8') as f:")
        lines.append(f"{prefix}    writer = csv.DictWriter(f, fieldnames={data_var}[0].keys())")
        lines.append(f"{prefix}    writer.writeheader()")
        lines.append(f"{prefix}    writer.writerows({data_var})")


# ── Mouse/Keyboard ────────────────────────────────────────────────

@_handler("keyCombo")
def _emit_keyCombo(node, extra, depth, prefix, by_parent, lines):
    keys = extra.get("keys", "")
    # Parse simple combos like "Ctrl+A" or "Ctrl+Shift+T"
    parts = [k.strip() for k in keys.split("+") if k.strip()]
    if parts:
        combo = ", ".join(f"Keys.{p}" for p in parts)
        lines.append(f"{prefix}tab.actions.key_down({combo}).key_up({combo})")
    else:
        lines.append(f"{prefix}# keyCombo: {keys}")


# ── Network ───────────────────────────────────────────────────────

@_handler("httpRequest")
def _emit_httpRequest(node, extra, depth, prefix, by_parent, lines):
    method = extra.get("method", "GET")
    url = (extra.get("url") or "").replace("'", "\\'")
    headers_str = extra.get("headers", "")
    body = extra.get("body", "")
    timeout = extra.get("timeout", 30)
    result_var = _var_ref(extra.get("resultVar", "response"))

    lines.append(f"{prefix}import requests")
    lines.append(f"{prefix}{result_var} = requests.{method.lower()}('{url}'")

    if headers_str:
        try:
            headers = json.loads(headers_str)
            lines.append(f"{prefix}    , headers={json.dumps(headers)}")
        except Exception:
            pass

    if body and method in ("POST", "PUT"):
        try:
            json_body = json.loads(body)
            lines.append(f"{prefix}    , json={json_body}")
        except Exception:
            b = body.replace("'", "\\'")
            lines.append(f"{prefix}    , data='{b}'")

    lines.append(f"{prefix}    , timeout={timeout})")


# ── AI ────────────────────────────────────────────────────────────

@_handler("callAiApp")
def _emit_callAiApp(node, extra, depth, prefix, by_parent, lines):
    app_type = extra.get("appType", "")
    inputs = extra.get("inputs", "{}")
    result_var = _var_ref(extra.get("resultVar", "aiResult"))
    lines.append(f"{prefix}# TODO: call AI app '{app_type}' with inputs={inputs}")
    lines.append(f"{prefix}{result_var} = None")


# ── Sub-workflow ──────────────────────────────────────────────────

@_handler("callWorkflow")
def _emit_callWorkflow(node, extra, depth, prefix, by_parent, lines):
    wf_id = extra.get("workflowId", 0)
    inputs = extra.get("inputs", "")
    lines.append(f"{prefix}# TODO: call workflow {wf_id}")


@_handler("return")
def _emit_return(node, extra, depth, prefix, by_parent, lines):
    expr = extra.get("resultExpr", "")
    if expr:
        try:
            parsed = json.loads(expr)
            expr_str = json.dumps(parsed, ensure_ascii=False)
            lines.append(f"{prefix}return {expr_str}")
        except Exception:
            lines.append(f"{prefix}return {expr}")
    else:
        lines.append(f"{prefix}return {{'total': len(_results), 'items': _results}}")


# ── Exception handling ────────────────────────────────────────────

@_handler("try")
def _emit_try(node, extra, depth, prefix, by_parent, lines):
    lines.append(f"{prefix}try:")
    for child in by_parent.get(node.id, []):
        _emit_dispatch(child, json.loads(child.extra) if child.extra else {}, depth + 1, by_parent, lines)


@_handler("catch")
def _emit_catch(node, extra, depth, prefix, by_parent, lines):
    err_var = _var_ref(extra.get("errorVar", "error"))
    lines.append(f"{prefix}except Exception as {err_var}:")
    for child in by_parent.get(node.id, []):
        _emit_dispatch(child, json.loads(child.extra) if child.extra else {}, depth + 1, by_parent, lines)


@_handler("endTry")
def _emit_endTry(node, extra, depth, prefix, by_parent, lines):
    pass  # Structural marker


# ── Custom ────────────────────────────────────────────────────────

@_handler("custom")
def _emit_custom(node, extra, depth, prefix, by_parent, lines):
    code = extra.get("code", "")
    desc = extra.get("description", "")
    if desc:
        lines.append(f"{prefix}# {desc}")
    for line in code.splitlines():
        lines.append(f"{prefix}{line}")


@_handler("executeJs")
def _emit_executeJs(node, extra, depth, prefix, by_parent, lines):
    script = extra.get("script", "").replace("'", "\\'")
    result_var = _var_ref(extra.get("resultVar", "jsResult"))
    lines.append(f"{prefix}{result_var} = tab.run_js('''{script}''')")
